public boolean ifUserCanMassEdit(User user, RequestParam rp) {
    boolean result = false;
    NUIForm form = AppManager.getFormPage(rp.getApname(), rp.getPath(), rp.getSheetIndex());
    if(form == null) return result;
    Set<String> groups = user.getGroups(rp.getApname());
    if(user.ifApManager(rp.getApname())){
      return true;
    }
    for(String group: groups) {
        int right = form.getRight(group);
        if(group.equals("SYSADMIN") || right == Const.ADMIN) {
            result = true;
            break;
        }
    }
    return result;
}

